import React, { useRef, useState, useEffect } from 'react';
import { Chessboard } from 'react-chessboard';
import { Chess } from 'chess.js';

export default function ChessBoard({
  roomId,
  fen,
  onMove,
  currentPlayer,
  whitePlayer,
  blackPlayer,
  boardOrientation = 'white',
  isSpectator = false,
  gameStatus,
  timerData,
}) {
  const gameRef = useRef(new Chess());
  const containerRef = useRef(null);
  const [boardWidth, setBoardWidth] = useState(400);
  const [whiteTime, setWhiteTime] = useState(30);
  const [blackTime, setBlackTime] = useState(30);

  // Responsive board sizing
  useEffect(() => {
    const updateSize = () => {
      if (containerRef.current) {
        const w = containerRef.current.offsetWidth;
        setBoardWidth(Math.min(w - 16, 560));
      }
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  // Update chess.js when fen changes
  useEffect(() => {
    if (fen && fen !== gameRef.current.fen()) {
      try {
        gameRef.current.load(fen);
      } catch (e) {
        console.error('Invalid FEN:', e);
      }
    }
  }, [fen]);

  // Timer countdown
  useEffect(() => {
    if (!timerData || gameStatus !== 'playing') return;

    const totalSeconds = Math.floor(timerData.timeMs / 1000);
    const elapsed = Math.floor((Date.now() - timerData.startedAt) / 1000);
    const remaining = Math.max(0, totalSeconds - elapsed);

    if (timerData.turn === 'w') {
      setWhiteTime(remaining);
    } else {
      setBlackTime(remaining);
    }

    const interval = setInterval(() => {
      if (timerData.turn === 'w') {
        setWhiteTime((prev) => Math.max(0, prev - 1));
      } else {
        setBlackTime((prev) => Math.max(0, prev - 1));
      }
    }, 1000);

    return () => clearInterval(interval);
  }, [timerData, gameStatus]);

  // Reset timer on new timerData
  useEffect(() => {
    if (timerData) {
      const totalSeconds = Math.floor(timerData.timeMs / 1000);
      if (timerData.turn === 'w') {
        setWhiteTime(totalSeconds);
        setBlackTime(30);
      } else {
        setBlackTime(totalSeconds);
        setWhiteTime(30);
      }
    }
  }, [timerData?.startedAt]);

  const canMakeMove = () => {
    if (isSpectator) return false;
    if (gameStatus !== 'playing') return false;
    if (!currentPlayer) return false;
    const turn = gameRef.current.turn();
    return (
      (turn === 'w' && currentPlayer.color === 'white') ||
      (turn === 'b' && currentPlayer.color === 'black')
    );
  };

  const onDrop = (sourceSquare, targetSquare) => {
    if (!canMakeMove()) return false;

    const game = gameRef.current;
    const move = game.move({
      from: sourceSquare,
      to: targetSquare,
      promotion: 'q',
    });
    if (!move) return false;

    onMove({
      from: sourceSquare,
      to: targetSquare,
      promotion: 'q',
      san: move.san,
    });

    return true;
  };

  const formatTime = (seconds) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s.toString().padStart(2, '0')}`;
  };

  const turn = gameRef.current.turn();
  const topPlayer = boardOrientation === 'white' ? blackPlayer : whitePlayer;
  const bottomPlayer = boardOrientation === 'white' ? whitePlayer : blackPlayer;
  const topTime = boardOrientation === 'white' ? blackTime : whiteTime;
  const bottomTime = boardOrientation === 'white' ? whiteTime : blackTime;
  const isTopTurn = boardOrientation === 'white' ? turn === 'b' : turn === 'w';
  const isBottomTurn = boardOrientation === 'white' ? turn === 'w' : turn === 'b';

  return (
    <div ref={containerRef} className="w-full flex flex-col items-center gap-3">
      {/* Top Player Bar */}
      <PlayerBar
        player={topPlayer}
        time={topTime}
        isActive={isTopTurn && gameStatus === 'playing'}
        color={boardOrientation === 'white' ? 'black' : 'white'}
        formatTime={formatTime}
      />

      {/* Timer progress bar */}
      {gameStatus === 'playing' && isTopTurn && (
        <div className="w-full progress-bar" style={{ maxWidth: boardWidth }}>
          <div
            className="progress-fill bg-gradient-to-r from-red-500 to-gold-500 timer-bar"
            style={{ width: `${(topTime / 30) * 100}%` }}
          />
        </div>
      )}

      {/* Board */}
      <div className={`rounded-xl overflow-hidden shadow-2xl shadow-black/50 transition-all duration-300 ${
        !canMakeMove() && !isSpectator && gameStatus === 'playing' ? 'opacity-80' : ''
      }`}>
        <Chessboard
          position={fen}
          onPieceDrop={onDrop}
          boardOrientation={boardOrientation}
          boardWidth={boardWidth}
          customBoardStyle={{
            borderRadius: '12px',
          }}
          customDarkSquareStyle={{ backgroundColor: '#1e293b' }}
          customLightSquareStyle={{ backgroundColor: '#334155' }}
          animationDuration={200}
          arePiecesDraggable={canMakeMove()}
        />
      </div>

      {/* Timer progress bar */}
      {gameStatus === 'playing' && isBottomTurn && (
        <div className="w-full progress-bar" style={{ maxWidth: boardWidth }}>
          <div
            className="progress-fill bg-gradient-to-r from-gold-500 to-emerald-500 timer-bar"
            style={{ width: `${(bottomTime / 30) * 100}%` }}
          />
        </div>
      )}

      {/* Bottom Player Bar */}
      <PlayerBar
        player={bottomPlayer}
        time={bottomTime}
        isActive={isBottomTurn && gameStatus === 'playing'}
        color={boardOrientation === 'white' ? 'white' : 'black'}
        formatTime={formatTime}
      />

      {/* Spectator Badge */}
      {isSpectator && (
        <div className="badge-purple mt-1">
          <span>👁️</span> Spectating
        </div>
      )}
    </div>
  );
}

function PlayerBar({ player, time, isActive, color, formatTime }) {
  return (
    <div
      className={`w-full max-w-[560px] flex items-center justify-between px-4 py-2.5 rounded-xl border transition-all duration-300 ${
        isActive
          ? 'bg-gold-500/10 border-gold-500/30 shadow-sm shadow-gold-500/10'
          : 'bg-navy-800/50 border-navy-700/30'
      }`}
    >
      <div className="flex items-center gap-3">
        {/* Avatar */}
        <div
          className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold ${
            color === 'white'
              ? 'bg-slate-200 text-slate-800'
              : 'bg-slate-800 text-slate-200 border border-slate-600'
          }`}
        >
          {player?.username?.charAt(0)?.toUpperCase() || '?'}
        </div>
        <div>
          <p className="text-sm font-semibold text-white">{player?.username || 'Waiting...'}</p>
          <p className="text-xs text-slate-500 capitalize">{color}</p>
        </div>
      </div>

      {/* Timer */}
      <div
        className={`px-3 py-1.5 rounded-lg font-mono text-sm font-bold ${
          isActive
            ? time <= 5
              ? 'bg-red-500/20 text-red-400 animate-pulse'
              : 'bg-gold-500/15 text-gold-400'
            : 'bg-navy-700/50 text-slate-400'
        }`}
      >
        {formatTime(time)}
      </div>
    </div>
  );
}
